const express = require('express');
const request = require('request');
const bodyParser = require('body-parser');
const morgan = require('morgan');

const app = express();

// Middleware to log requests
app.use(morgan(':remote-addr - :remote-user ":method :url HTTP/:http-version" :status :res[content-length] ":referrer" ":user-agent"'));

// Middleware for reading json from requests
app.use(bodyParser.json());

// Middleware for API key auth
app.use((req, res, next) => {
    let apiKey = req.query.api_key;

    if (!apiKey) {
        return res.status(400).send({ error: 'Missing api_key query parameter' });
    }

    req.headers['api_key'] = apiKey;

    next();
});

app.all('*', (req, res) => {
    let { baseUrl, url, method, headers, body } = req;

    // Generate the forwarded url while removing the api_key query parameter
    let forwardedUrl = `${baseUrl}${url}`.replace(/(\?)?(&)?api_key=[^&]+&?/, '$1');

    request({
        url: forwardedUrl,
        method: method,
        headers: headers,
        body: JSON.stringify(body)
    }).pipe(res);
});

const PORT = process.env.PORT || 5000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));